  const lanes = [-1.55, 0, 1.55];
  const runnerZ = 2.8;
  const recycleZ = 4.3;
  const farZ = -16.5;
  const isRecord = (value: unknown): value is Record<string, unknown> => typeof value === "object" && value !== null;
