      phase: "failed",
      score: Math.floor(score),
      coins,
      distance,
      speed,
      scoreText: `Score ${Math.floor(score)}`,
      coinsText: `Coins ${Math.min(coins, objectiveCoins)}/${objectiveCoins}`,
